function instrumented_invoke(ctx, request, call):
    chain_span = tracer.start("mw.chain", n=len(MW))
    sampled = rand() < 0.05                            # verbose payload sampling
    try:
        for mw in MW:
            s = tracer.start("mw.req", name=mw.name)
            request = mw.process_request(ctx, request)
            s.end()
            if request.short_circuit:
                audit.emit("mw.short_circuit", {by: mw.name, ts: now()})
                return request.short_circuit_response

        response = call(request)

        for mw in reversed(MW):
            response = mw.process_response(ctx, request, response)

        if sampled:
            audit.emit("mw.trace", pii.scrub({
                req: request.summary(), resp: response.summary(),
            }), ttl_days=14)
        dashboard.publish("mw.chain.latency_ms", chain_span.elapsed_ms())
        return response
    finally:
        chain_span.end()

# Why this works: per-middleware spans expose where time is spent, while
# sampling and PII scrub keep the audit affordable and safe.
# Related: see `pii-redaction`, `decision-log`, `kill-switch`.

class PolicyGateMW:                                   # related: policy-as-code-gate
    name = "policy_gate"
    function process_request(ctx, req):
        decision = policy.evaluate({
            actor: ctx.actor, action: req.action,
            resource: req.resource, tier: ctx.tier,
        })
        audit.emit("policy.decision", {
            req_id: ctx.req_id, allowed: decision.allow,
            rule: decision.rule_id, ts: now(),
        })
        if not decision.allow:
            req.short_circuit = true
            req.short_circuit_response = Denied(decision.reason)
        return req

    function process_response(ctx, req, resp): return resp
    function process_error(ctx, req, err):     return null

runtime.bind(MiddlewareChain([
    PIIRedactionMW(), PolicyGateMW(), RateLimitMW(), DecisionLogMW(),
]))

