ARTIFACT_TTL = {plan: 90, tool_call_trace: 30,
                guardrail_decision: 365, reflection: 30}
DEEP_EVAL_RATE = 0.10

function emit_and_score(node, artifact, expected=null):
    safe = pii.scrub(artifact)
    audit.emit("artifact." + node, safe, ttl_days=ARTIFACT_TTL[node])

    if rand() < DEEP_EVAL_RATE:
        v = ARTIFACT_RUBRICS[node].score(artifact, expected)
        audit.emit("artifact.eval", {
            node: node, passed: v.passed, score: v.score, ts: now(),
        })
        dashboard.publish("artifact.pass_rate." + node, v.passed)
        if not v.passed and v.severity >= HIGH:
            alert.page("artifact regression", node=node)
        return v
    return null

function run_pipeline(task):
    plan = planner.plan(task);       emit_and_score("plan", plan)
    trace = executor.run(plan);      emit_and_score("tool_call_trace", trace)
    g = guardrails.check(trace);     emit_and_score("guardrail_decision", g)
    r = critic.review(trace);        emit_and_score("reflection", r)
    return composer.finalise(plan, trace, g, r)

