function prod_choose(request):
    draws = {vid: sample_beta(a.alpha, a.beta) for vid, a in arms.items()}
    chosen = argmax(draws)
    audit.emit("bandit.assign", {
        ts: now(), req_id: request.id,
        variant: chosen, draws: draws,
        user_hash: hash(request.user_id),
    }, ttl_days=ASSIGN_TTL_DAYS)
    return chosen

function prod_record_reward(req_id, variant, reward):
    a = arms[variant]
    a.alpha += reward; a.beta += (1 - reward); a.n += 1
    audit.emit("bandit.reward", {
        ts: now(), req_id: req_id, variant: variant, reward: reward,
    })
    means = {vid: x.alpha / (x.alpha + x.beta) for vid, x in arms.items()}
    dashboard.publish("bandit.posterior_mean", means)
    dashboard.publish("bandit.regret", cumulative_regret(arms))
    if min(x.n for x in arms.values()) < MIN_N_FLOOR and elapsed() > STUCK_AT:
        alert.page("bandit: arm starvation", arms=arms)

