function gate_pinned(version, evals):                 # related: prompt-versioning
    prompts = prompt_registry.snapshot(version)
    blocking = [e for e in evals if e.tier == "blocking"]
    results = run_evals(version, blocking)

    for r in results:
        audit.emit("eval.contract.pinned", {
            ts: now(),
            version: version,
            prompt_versions: prompts,
            eval_id: r.id,
            passed: r.passed,
            score: r.score,
        })

    failed = [r for r in results if not r.passed]
    if failed:
        report = {
            blocked_release: version,
            offending_prompts: prompts,
            failed_evals: [r.id for r in failed],
        }
        decision_log.append({id: "block." + version, evidence: report})
        return Reject(report)
    return Approve(version)

