function run_eval_harness(champion, challenger, dataset, scorers):
    results = {champion: [], challenger: []}
    for example in dataset:                # (input, expected)
        for version in [champion, challenger]:
            output = version.run(example.input)
            scored = {s.name: s(output, example.expected) for s in scorers}
            results[version].append({example: example, scored: scored})

    deltas = compare(results[champion], results[challenger])
    decision = promote if all_lifts_non_negative(deltas) else block
    return {results: results, deltas: deltas, decision: decision}

