function harness_run_prod(champion, challenger, dataset, scorers):
    ds_hash = sha256(dataset.serialize())
    span = tracer.start("harness.run",
                        champion=champion.id, challenger=challenger.id)
    out = {champion: [], challenger: []}

    for ex in dataset:
        for v in [champion, challenger]:
            o = v.run(ex.input)
            scored = {s.name: s(o, ex.expected) for s in scorers}
            out[v].append({input_hash: sha256(ex.input), scored: scored})

    deltas = compare(out[champion], out[challenger])
    audit.emit("harness.result", {
        ts: now(),
        champion: champion.id, challenger: challenger.id,
        dataset_hash: ds_hash,
        deltas: deltas,
    }, ttl_days=HARNESS_TTL_DAYS)
    dashboard.publish("harness.delta", deltas)
    span.end()
    if not all_lifts_non_negative(deltas):
        alert.page("harness regression", deltas=deltas)
        return Block(deltas)
    return Promote(challenger)

