function harness_with_judge(champion, challenger, dataset):
    rubric = rubric_registry.get("answer-rubric", "v3")  # related: llm-as-judge
    out = {champion: [], challenger: []}

    for ex in dataset:
        for v in [champion, challenger]:
            o = v.run(ex.input)
            verdict = judge_model.score(
                input=ex.input, output=o, rubric=rubric,
            )
            audit.emit("harness.judge", {
                version: v.id, ex_hash: sha256(ex.input),
                rubric_version: "v3", score: verdict.score,
