            out[v].append(verdict)

    decision = (mean(out[challenger]) > mean(out[champion])
                and judge_calibration_ok())
    audit.emit("harness.decision", {
        champion_mean: mean(out[champion]),
        challenger_mean: mean(out[challenger]),
        rubric: "answer-rubric@v3",
        decision: decision,
    })
    return Promote(challenger) if decision else Hold()

