# Why this works: signing on write and verifying on read closes the gap
# between 'registry says hash X' and 'process loaded hash X'; rollback is
# a tracked event, not a silent deploy.
# Related: see `own-your-prompts`, `provenance-ledger`, `decision-log`.

REQUIRED_FIELDS = ["ts", "actor", "action", "target",
                   "justification", "diff_hash"]

function append_event(event):
    for f in REQUIRED_FIELDS:
        if f not in event:
            raise IncompleteEvent(missing=f)
    event.id = monotonic_id()
    ledger.append_immutable(event)         # append-only store
    return event.id

function rollback(event_id):
    event = ledger.get(event_id)
    inverse = compute_inverse(event)       # uses diff_hash + target
    return append_event({
        ts: now(),
        actor: "system:rollback",
        action: inverse.action,
        target: event.target,
        justification: f"rollback of {event_id}",
        diff_hash: inverse.diff_hash,
    })

function append_with_lineage(event):                  # related: lineage-tracking
    lin = lineage.current()
    # {prompt_version, model_id, index_version, tool_versions}
    enriched = merge(event, {lineage: lin})

    for f in REQUIRED_FIELDS:
        if f not in enriched: raise IncompleteEvent(missing=f)
    enriched.id = monotonic_id()
    enriched.ts = now()
    enriched.lineage_hash = sha256(canonical(lin))
    ledger.append_immutable(enriched)
    audit.emit("ledger.linked", {
        event_id: enriched.id,
        lineage_hash: enriched.lineage_hash,
    })
    return enriched.id

function reconstruct(event_id):
    e = ledger.get(event_id)
    lin = e.lineage
    return {
        when:     e.ts,
        what:     e.action,
        why:      e.justification,
        produced_by: {
            prompt: lin.prompt_version,
            model: lin.model_id,
            index: lin.index_version,
        },
    }

# Why this works: every ledger event carries enough lineage to replay or
# explain it without re-collecting context from elsewhere.
