SCORE_TTL_DAYS = 90

function handle_request_prod(request):
    output = agent.run(request.input)
    respond(request, output)                          # user gets answer first
    scoring_stream.publish(pii.scrub({
        request_id: request.id,
        input: request.input,
        output: output,
        context: request.context,
    }))

function scorer_worker_prod(scorers):
    for msg in scoring_stream.consume():
        for s in scorers:
            sc = s.score(msg.input, msg.output, msg.context)
            audit.emit("scorer.live", {
                ts: now(),
                request_id: msg.request_id,
                scorer: s.name,
                score: sc.value,
            }, ttl_days=SCORE_TTL_DAYS)
            dashboard.publish("scorer." + s.name + ".score", sc.value)
            if sc.value < s.low_threshold:
                review_queue.enqueue(msg.request_id,
                                     priority=s.low_threshold - sc.value)
                alert.notify("quality-team", scorer=s.name,
                             request_id=msg.request_id)

# Why this works: scoring runs out-of-band so user latency is untouched;
# low scores route to review, never to regen, keeping cost bounded.
# Related: see `pii-redaction`, `scorer-live-monitoring`, `evaluator-optimizer`.

function handle_request(request, champion, challenger, sample_rate=0.05):
    champ_out = champion.run(request.input)
    respond(request, champ_out)              # user sees ONLY champion

    if rand() < sample_rate:
        # run shadow off the user's critical path
        spawn(async () -> {
            chall_out = challenger.run(request.input)
            diff = {
                request_id: request.id,
                judge_score: llm_judge(request.input, chall_out, champ_out),
                tool_match:  champ_out.tool_calls == chall_out.tool_calls,
                latency_d:   chall_out.latency - champ_out.latency,
                cost_d:      chall_out.cost    - champ_out.cost,
            }
            shadow_metrics.write(diff)
        })

function promotion_decision(window):
    m = shadow_metrics.aggregate(window)
    return "promote" if m.judge_lift > 0 and m.cost_d <= 0 else "hold"

