RECONTACT_WINDOW_HOURS = 48
CSAT_FLOOR = 4.0          # set to None to skip the CSAT condition
GATE_THRESHOLD = 0.55     # rollout requires a true-resolution rate at or above this

def gated_resolution_rate(interactions):
    handled = len(interactions)
    if handled == 0:
        return 0.0
    resolved = 0
    for it in interactions:
        if not it.deflected:
            continue                              # session never ended on its own
        if correctness_scorer(it).is_wrong:
            continue                              # subtract: confidently-wrong answer
        if recontact_within(it, RECONTACT_WINDOW_HOURS):
            continue                              # subtract: customer came back, same problem
        if CSAT_FLOOR is not None and it.csat is not None and it.csat < CSAT_FLOOR:
            continue                              # worn-down departure is not a win
        resolved += 1
    return resolved / handled

def recontact_within(it, hours):
    # un-gameable signal: a later conversation linked to the SAME customer + problem
    later = lookup_followups(customer=it.customer, topic=it.topic,
                             after=it.closed_at, within_hours=hours)
    return len(later) > 0

def rollout_gate(window):
    deflection = sum(1 for it in window if it.deflected) / len(window)
    true_rate = gated_resolution_rate(window)
    report(raw_deflection=deflection, true_resolution=true_rate)  # deflection is throughput, not quality
    if true_rate < GATE_THRESHOLD:
        block(f"true resolution {true_rate:.0%} < gate {GATE_THRESHOLD:.0%} "
              f"(raw deflection {deflection:.0%} was inflated)")
    return true_rate >= GATE_THRESHOLD

# ANTI-PATTERN: 'pilot' is an open-ended status; scope grows, the gate never fires
pilot = Deployment(status="pilot", scope=["desk-A"], mode="advisory")

def on_expansion_request(pilot, req):
    # each increment looks too small to re-classify, so it is just added
    pilot.scope.append(req.user_group)        # + users
    pilot.decision_types |= req.decision_types # + decision types
    if req.auto_action:
        pilot.mode = "actioned"               # outputs now acted on directly
    log("pilot expansion")                     # never logged as a production launch
    return pilot                              # status stays "pilot" forever

# REMEDY: time-box the pilot and define triggers that FORCE a go-live decision
TRIGGERS = {
    "users": 25, "traffic_share": 0.10,
    "stakes": "consequential", "irreversible_outputs": True,
}

def on_expansion_request_gated(pilot, req, now):
    candidate = pilot.with_added(req)
    if now > pilot.expires_at or crosses_any(candidate, TRIGGERS):
        # crossing a trigger is a GO-LIVE event: graduate or retire, do not just grow
        decision = production_governance.review(candidate)  # sign-off, risk assessment, named owner
        if decision != "approved":
            raise ExpansionBlocked("must graduate to production or retire; cannot stay a pilot")
        return candidate.promote(status="production", owner=decision.named_owner)
    return pilot.with_added(req)              # below all triggers: still a real pilot

def crosses_any(d, triggers):
    return (len(d.scope) >= triggers["users"]
            or d.traffic_share >= triggers["traffic_share"]
            or d.stakes == triggers["stakes"]
            or d.irreversible_outputs == triggers["irreversible_outputs"])

def deploy(agent_config):
    cert = auditor.certify(agent_config, standard="AIUC-1")   # 6 pillars, 130 controls
    if not cert.passed:
        return BLOCKED(cert.findings)
    policy = underwriter.bind(cert, telemetry=telemetry_contract)
    registry.record(agent_config.hash, cert, policy)
    return launch(agent_config)

def on_config_change(new_config):
    if material_change(registry.certified_hash, new_config):    # model, tools, autonomy scope
        policy.suspend()                                        # uninsured until re-certified
        return deploy(new_config)                               # re-audit, re-bind

def on_incident(incident):
    telemetry.emit(incident)
    if incident.age > policy.reporting_window:
        log.warn("late report risks denial")                   # continuing obligation
    claims.file(incident) if incident.third_party_loss else None
